// 2.8.4 | 2023-11-06 | raj | STRY0146507 - Certification Support- Placeholder - split into before and after and update children in after rule
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	tcs = new TaskerCommonScriptingMethods();
	try{
		if(current.tasker_type.work_type != "review_item") { //Standard Task Type
			if(!(current.reviewer_manual_update) || current.u_reviewer == "") {
				if(current.isNewRecord() || current.u_reviewer == "") {
					if(current.parent && current.parent.assigned_to) {
						// set reviewer to parent assigned
						current.u_reviewer = current.parent.assigned_to;
						// if the assigned is not valid
					} else if(current.parent) {
						// set the task owner
						current.u_reviewer = current.parent.u_task_requester;
					}
					// parent is invalid - top task
					if(!current.parent && current.originator){
						// set originator
						current.u_reviewer = current.originator;
					}
					current.reviewer_manual_update = false;
				}
			}
			// for review types, lock reviewer to assigned_to
			// STRY0146507 - Moved into an event to move out of before
			// fire event to update subtasks and set the reviewer to the new assinged member
			gs.eventQueue("x_153465_discovert.Task_AsignMem_Chg_Rvw",current,'','');

		} else {
			current.u_reviewer = current.assigned_to;
		}
	}catch(e) {
		gs.error("Exception - " + e.message);
	}
})(current, previous);
